// Get the full list of vulnerabilities from the CISA node
const kevItems = $items("CISA")[0].json.vulnerabilities || [];

// Filter safely, checking if vendor_product exists
const filtered = kevItems.filter(item => {
    const vendorProduct = item.vendor_product || "";
    const vendorVersion = item.vendor_product_version || "";

