const html = $input.first().json.data || '';
const url = $('source loop').first().json.citation_url || 'unknown';

// Heuristics to detect blocked/forbidden pages
const blockedPatterns = [
  /403 Forbidden/i,
  /Access Denied/i,
  /You don't have permission to access/i,
  /Cloudflare/i
];

const isBlocked = blockedPatterns.some(rx => rx.test(html));

if (isBlocked || !html.trim()) {
  // Skip this page: return empty IOCs
  return [{
    json: {
      citation_url: url,
      skipped: true,
      reason: 'Blocked or empty page',
      main_content: '',
      cves: [],
      ips: [],
      domains: [],
      hashes: []
    }
  }];
}

// Clean HTML: remove scripts/styles and tags
let cleaned = html.replace(/<script[\s\S]*?<\/script>/gi, '')
                  .replace(/<style[\s\S]*?<\/style>/gi, '')
                  .replace(/<\/?[^>]+(>|$)/g, ' ')
                  .replace(/\s+/g, ' ')
                  .trim();

// Extract CVEs
const cves = [...cleaned.matchAll(/CVE-\d{4}-\d{4,7}/gi)].map(m => m[0]);

// Extract IPv4 addresses
const ips = [...cleaned.matchAll(/\b(?:\d{1,3}\.){3}\d{1,3}\b/g)].map(m => m[0]);

// Extract domains (basic)
const domains = [...cleaned.matchAll(/\b(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+[a-z]{2,}\b/gi)].map(m => m[0]);

// Extract common hashes (MD5, SHA1, SHA256)
// Match MD5, SHA1, SHA256 (hexadecimal, uppercase or lowercase)
const hashes = [...cleaned.matchAll(/(?:\b|=|:)\s*([a-fA-F0-9]{32}|[a-fA-F0-9]{40}|[a-fA-F0-9]{64})\b/g)].map(m => m[1]);


return [{
  json: {
    citation_url: url,
    skipped: false,
    main_content: cleaned,
    cves: Array.from(new Set(cves)),
    ips: Array.from(new Set(ips)),
    domains: Array.from(new Set(domains)),
    hashes: Array.from(new Set(hashes))
  }
}];

const iocs = $('Merge IOCs').first().json.combined_iocs;

return [
  { json: { type: "cve", value: iocs.cves } },
  { json: { type: "ip", value: iocs.ips } },
  { json: { type: "domain", value: iocs.domains } },
  { json: { type: "hash", value: iocs.hashes } }
];

// This node should run AFTER the loop ends
const all = {
  cves: new Set(),
  ips: new Set(),
  domains: new Set(),
  hashes: new Set(),
};

for (const item of items) {
  if (item.json.skipped) continue; // skip blocked/empty pages
  (item.json.cves || []).forEach(c => all.cves.add(c));
  (item.json.ips || []).forEach(i => all.ips.add(i));
  (item.json.domains || []).forEach(d => all.domains.add(d));
  (item.json.hashes || []).forEach(h => all.hashes.add(h));
}

return [{
  json: {
    combined_iocs: {
      cves: [...all.cves],
      ips: [...all.ips],
      domains: [...all.domains],
      hashes: [...all.hashes],
    }
  }
}];

function isValidPublicIPv4(ip) {
  // Basic IPv4 format check
  if (!/^(?:\d{1,3}\.){3}\d{1,3}$/.test(ip)) return false;

  const parts = ip.split('.').map(Number);

  // Each octet must be 0–255
  if (!parts.every(p => p >= 0 && p <= 255)) return false;

  // Exclude special/private ranges
  if (
    parts[0] === 10 ||                                  // 10.0.0.0/8
    (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) || // 172.16.0.0/12
    (parts[0] === 192 && parts[1] === 168) ||            // 192.168.0.0/16
    (parts[0] === 169 && parts[1] === 254) ||            // Link-local
    parts[0] === 127 ||                                  // Loopback
    ip === '255.255.255.255'                              // Broadcast
  ) {
    return false;
  }

  return true;
}

return items.filter(item => {
  const v = item.json.value;
  return v && typeof v === 'string' && isValidPublicIPv4(v.trim());
});

// Flatten input to an array of domain strings
const domains = ($input.all() || []).flatMap(item => item.json.value || []);

// List of common TLDs (can be expanded or use a library in production)
const tlds = ['com','org','net','edu','gov','io','co','info','biz','me','us','uk','de','fr','in','ru','cn'];

// Keep only valid public domains
const validDomains = domains.filter(d => {
  if (!d || d.trim() === '') return false;
  d = d.toLowerCase().trim();
  const parts = d.split('.');
  return parts.length >= 2 && tlds.includes(parts[parts.length -1]);
});

// Skip if nothing valid
if (validDomains.length === 0) return [];

// Output for looping
return validDomains.map(d => ({ json: { value: d } }));

return items.map(item => {
  const d = item.json.data || {};
  const ip = d.ipAddress || item.json.ip || 'N/A';

  return {
    json: {
      ioc: ip,
      source: "AbuseIPDB",
      ip: ip,
      abuse_score: d.abuseConfidenceScore || 0,
      country: d.countryCode || "N/A",
      reports: d.totalReports || 0,
      usageType: d.usageType || "N/A",
      isPublic: d.isPublic || false,
      isTor: d.isTor || false
    }
  };
});

return items.map(item => ({
  json: {
    ioc: item.json.value,
    source: "VirusTotal-DNS",
    vt_result: item.json.data?.attributes?.last_analysis_stats || {},
    malicious_score: item.json.data?.attributes?.last_analysis_stats?.malicious || 0
  }
}));

// Flatten all arrays from multiple runs
let all = [];

for (const item of items) {
  if (Array.isArray(item.json)) {
    all.push(...item.json);
  } else {
    all.push(item.json);
  }
}

return [{ json: { combined_data: all } }];

return items.map(item => ({
  json: {
    ioc: item.json.value,
    source: "VirusTotal-Hash",
    vt_result: item.json.data?.attributes?.last_analysis_stats || {},
    malicious_score: item.json.data?.attributes?.last_analysis_stats?.malicious || 0
  }
}));

// Get the flattened array from previous node
const combined = items[0].json.combined_data || [];

// Group data by IOC
const grouped = {};

for (const entry of combined) {
  const ioc = entry.ioc || "unknown";

  if (!grouped[ioc]) {
    grouped[ioc] = {
      ioc: ioc,
      sources: {}
    };
  }

  // Add source-based enrichment under the IOC
  const src = entry.source || "Unknown-Source";

  grouped[ioc].sources[src] = entry;
}

// Convert grouped dictionary to an array
const results = Object.values(grouped);

return results.map(r => ({ json: r }));

// Combine all IOCs and their enrichments into a readable summary
const data = items.map(i => i.json);

let report = "Threat Intelligence Summary Input:";

for (const entry of data) {
  report += `IOC: ${entry.ioc}\n`;

  for (const [source, details] of Object.entries(entry.sources || {})) {
    report += `  Source: ${source}\n  Details: ${JSON.stringify(details, null, 2)}\n`;
  }

  report += "\n";
}

// You can also inject product/version dynamically (if earlier nodes provided them)
const product = $('Input validation').first().json.product || "Unknown Product";
const version = $('Input validation').first().json.version|| "N/A";

const finalPrompt = `
You are a threat intelligence analyst.
For product: ${product}, version: ${version},
use the following enriched IOC details to generate a concise summarized report of findings.

${report}
`;

return [{ json: { prompt: finalPrompt } }];

const prompt = `
You are a threat intelligence analyst.
For product: $('Input validation').first().json.product, version: $('Input validation').first().json.version
use the following enriched IOC details to generate a concise summarized report of findings.

Threat Intelligence Summary Input:
${$json.prompt || JSON.stringify($json.combined_results || $json, null, 2)}
`;

return [
  {
    json: {
      model: "sonar",
      messages: [
        {
          role: "system",
          content:
            "You are a cybersecurity threat intelligence analyst. Summarize and explain the following IOC results in a short, clear threat report."
        },
        {
          role: "user",
          content: prompt
        }
      ]
    }
  }
];

return [
  {
    json: {
      model: $json.model,
      messages: $json.messages
    }
  }
];

// Extract and format Perplexity API output for Telegram
const data = $json;
let report = '';
let citations = '';
let sources = '';

try {
  // Extract main report text
  report = data.choices?.[0]?.message?.content?.trim() || 'No summary generated.';

  // Format citations (if available)
  if (data.citations && data.citations.length > 0) {
    citations = data.citations.map((c, i) => `🔗 [Source ${i + 1}](${c})`).join('\n');
  } else {
    citations = 'No citations found.';
  }

  // Add visible source list from search results (if any)
  if (data.search_results && data.search_results.length > 0) {
    sources = data.search_results
      .map((r, i) => `[${r.title || 'Untitled Source'}](${r.url})`)
      .join('\n');
  }
} catch (e) {
  report = 'Error extracting Perplexity output: ' + e.message;
}

// Optional: derive a quick "Threat Level" guess from report keywords
let threatLevel = 'Unknown';
if (/critical|high|severe/i.test(report)) threatLevel = '🔴 High';
else if (/medium|moderate/i.test(report)) threatLevel = '🟠 Medium';
else if (/low|minor|benign/i.test(report)) threatLevel = '🟢 Low';

return [{
  json: {
    text: `*Threat Intelligence Summary*\n\n${report}\n\n*Threat Level:* ${threatLevel}\n\n${citations}\n\n${sources}`
  }
}];

// Get the incoming Telegram message text
const text = $json["message"]?.text || "";

// Regex to capture product and version
const pattern = /analyze latest threat intel on\s+([\w-]+)\s+([\d.]+)/i;
const match = text.match(pattern);

if (!match) {
  return [{ json: { product: null, version: null, keywords: [], note: "Invalid format" } }];
}

// Define default keywords for threat intel search
const keywords = ["CVE", "Vulnerability", "Exploit", "Threat", "Malware"];

// Return structured object
return [
  {
    json: {
      product: match[1],
      version: match[2],
      keywords: keywords
    }
  }
];

return items.map(item => {
  const hash = item.json.sha256s?.[0] || item.json.value || "unknown";
  const reports = item.json.reports || [];
  const errorMsg = item.json.error?.message || null;

  return {
    json: {
      ioc: hash,
      source: "HybridAnalysis-Hash",
      verdicts: reports.map(r => ({
        id: r.id || "N/A",
        environment: r.environment_description || "N/A",
        state: r.state || "N/A",
        verdict: r.verdict || "N/A"
      })),
      report_count: reports.length || 0,
      error: errorMsg
    }
  };
});

const raw =
  $input.first().json.text ||
  'No report generated';

// 1. Remove Markdown bold, headers, emojis
let text = raw
  .replace(/\*\*/g, '')          // remove **
  .replace(/^#+\s*/gm, '')       // remove # headers
  .replace(/\r\n/g, '\n');

// 2. Convert Markdown tables to readable text
// Detect table rows
const lines = text.split('\n');
let output = [];
let inTable = false;

for (let line of lines) {
  if (line.includes('|') && line.includes('---')) {
    inTable = true;
    continue;
  }

  if (line.includes('|') && inTable) {
    const cols = line.split('|').map(c => c.trim()).filter(Boolean);

    if (cols.length >= 3) {
      output.push(
        `• ${cols[0]} | ${cols[1]} | Severity: ${cols[2]} | Updated: ${cols[3] || 'N/A'}`
      );
    }
    continue;
  }

  if (inTable && !line.includes('|')) {
    inTable = false;
  }

  output.push(line);
}

text = output.join('\n');

// 3. Improve section spacing
text = text
  .replace(/Threat Intelligence Summary/gi, '\nTHREAT INTELLIGENCE SUMMARY\n')
  .replace(/Key Vulnerabilities/gi, '\nKEY VULNERABILITIES\n')
  .replace(/Recommendations/gi, '\nRECOMMENDATIONS\n')
  .replace(/Threat Level:/gi, '\nTHREAT LEVEL:');

// 4. Clean excessive newlines
text = text.replace(/\n{3,}/g, '\n\n').trim();

// 5. Telegram message length safety
const MAX = 4000;
if (text.length > MAX) {
  text = text.slice(0, MAX) + '\n\n[Truncated]';
}

return [
  {
    json: {
      telegram_report: text
    }
  }
];
